def stats(numbers):
    return {
        'min': min(numbers),
        'max': max(numbers),
        'sum': sum(numbers),
        'average': sum(numbers) / len(numbers),
        'count': len(numbers)
    }

result = stats([10, 20, 30, 40, 50])
print(result)

def calculate(operation, *args):
    if operation == 'add':
        return sum(args)
    elif operation == 'multiply':
        result = 1
        for n in args:
            result *= n
        return result
    elif operation == 'max':
        return max(args)
    elif operation == 'min':
        return min(args)

print(f"add: {calculate('add', 1, 2, 3, 4, 5)}")
print(f"multiply: {calculate('multiply', 1, 2, 3, 4, 5)}")
print(f"max: {calculate('max', 1, 2, 3, 4, 5)}")
print(f"min: {calculate('min', 1, 2, 3, 4, 5)}")

def is_palindrome(s):
    s = s.lower().replace(' ', '')
    if len(s) <= 1:
        return True
    if s[0] != s[-1]:
        return False
    return is_palindrome(s[1:-1])

print(f"racecar: {is_palindrome('racecar')}")
print(f"A man a plan a canal Panama: {is_palindrome('A man a plan a canal Panama')}")
print(f"hello: {is_palindrome('hello')}")

def power(base, exp):
    if exp == 0:
        return 1
    return base * power(base, exp - 1)

print(f"2^10 = {power(2, 10)}")
print(f"3^4 = {power(3, 4)}")
print(f"5^0 = {power(5, 0)}")

def flatten(lst):
    result = []
    for item in lst:
        if isinstance(item, list):
            result.extend(flatten(item))
        else:
            result.append(item)
    return result

nested = [1, [2, 3], [4, [5, 6]], 7]
print(flatten(nested))

def pipeline(*functions):
    def apply(value):
        result = value
        for func in functions:
            result = func(result)
        return result
    return apply

def double(x):
    return x * 2

def increment(x):
    return x + 1

def square(x):
    return x ** 2

transform = pipeline(double, increment, square)
print(f"pipeline result: {transform(3)}")
print(f"pipeline result: {transform(4)}")
